/**
 * Create an Interval from an ISO 8601 string.
 * Accepts `<start>/<end>`, `<start>/<duration>`, and `<duration>/<end>` formats.
 * @param {string} text - the ISO string to parse
 * @param {Object} [opts] - options to pass {@link DateTime#fromISO} and optionally {@link Duration#fromISO}
 * @see https://en.wikipedia.org/wiki/ISO_8601#Time_intervals
 * @return {Interval}
 */
static fromISO(text, opts) {
  const [s, e] = (text || "").split("/", 2);
  if (s && e) {
    let start, startIsValid;
    try {
      start = DateTime.fromISO(s, opts);
      startIsValid = start.isValid;
    } catch (e) {
      startIsValid = false;
    }

    let end, endIsValid;
    try {
      end = DateTime.fromISO(e, opts);
      endIsValid = end.isValid;
    } catch (e) {
      endIsValid = false;
    }

    if (startIsValid && endIsValid) {
      return Interval.fromDateTimes(start, end);
    }

    if (startIsValid) {
      const dur = Duration.fromISO(e, opts);
      if (dur.isValid) {
        return Interval.after(start, dur);
      }

      // Try to parse end as a partial ISO string and merge with start
      // According to ISO 8601, missing elements in end should be taken from start
      let partialEnd;
      try {
        // Try parsing with start's date components as defaults
        partialEnd = DateTime.fromISO(
          `${start.toISODate()}T${e.replace(/^T?/, "")}`,
          opts
        );
        if (partialEnd.isValid) {
          return Interval.fromDateTimes(start, partialEnd);
        }
      } catch (ex) {
        // If that fails, try parsing as just a date with start's time
        try {
          partialEnd = DateTime.fromISO(e, opts);
          if (!partialEnd.isValid) {
            // Try combining start's year if end looks like a month-day
            const startDate = start.toISODate();
            const startYear = startDate.split("-")[0];
            partialEnd = DateTime.fromISO(`${startYear}-${e}`, opts);
          }
          if (partialEnd.isValid) {
            return Interval.fromDateTimes(start, partialEnd);
          }
        } catch (ex2) {
          // Ignore
        }
      }
    } else if (endIsValid) {
      const dur = Duration.fromISO(s, opts);
      if (dur.isValid) {
        return Interval.before(end, dur);
      }
    }
  }
  return Interval.invalid("unparsable", `the input "${text}" can't be parsed as ISO 8601`);
}

