static fromISO(text, opts) {
  const [s, e] = (text || "").split("/", 2);
  if (s && e) {
    let start, startIsValid;
    try {
      start = DateTime.fromISO(s, opts);
      startIsValid = start.isValid;
    } catch (e) {
      startIsValid = false;
    }

    let end, endIsValid;
    try {
      end = DateTime.fromISO(e, opts);
      endIsValid = end.isValid;
    } catch (e) {
      endIsValid = false;
    }

    if (startIsValid && endIsValid) {
      // According to ISO 8601, if end is missing date components, they should be taken from start
      // Check if the end string looks like it's only time (no date separator like '-' or year digits)
      // Time-only patterns: HH, HH:MM, HH:MM:SS, etc.
      const looksLikeTimeOnly = /^T?\d{2}(:\d{2}(:\d{2}(\.\d+)?)?)?$/.test(e) && !/^\d{4}/.test(e) && !/-/.test(e);

      // Check if the end string looks like a partial date (month-day like "05-15" or "--05-15")
      // This matches MM-DD patterns without a year prefix
      const looksLikePartialDate = /^--?\d{2}-\d{2}/.test(e) || (/^\d{2}-\d{2}$/.test(e) && !/^\d{4}/.test(e));

      if (looksLikeTimeOnly) {
        // Re-parse end with start's date components and timezone
        try {
          // Use start's ISO string with timezone, then replace time part
          const startISO = start.toISO();
          const timeMatch = startISO.match(/T(.+)$/);
          let isoString;

          if (timeMatch) {
            // Replace time but keep timezone offset
            const timezoneMatch = timeMatch[1].match(/([+-]\d{2}:\d{2}|Z)$/);
            const timezone = timezoneMatch ? timezoneMatch[1] : "";
            isoString = `${start.toISODate()}T${e.replace(/^T?/, "")}${timezone}`;
          } else {
            isoString = `${start.toISODate()}T${e.replace(/^T?/, "")}`;
          }

          const combinedEnd = DateTime.fromISO(isoString, opts);
          if (combinedEnd.isValid) {
            return Interval.fromDateTimes(start, combinedEnd);
          }
        } catch (ex) {
          // If combining fails, fall through to use the originally parsed end
        }
      } else if (looksLikePartialDate) {
        // Re-parse end with start's year
        try {
          const startYear = start.year;
          const normalizedEnd = e.replace(/^--?/, "");
          const combinedEnd = DateTime.fromISO(`${startYear}-${normalizedEnd}`, opts);
          if (combinedEnd.isValid) {
            return Interval.fromDateTimes(start, combinedEnd);
          }
        } catch (ex) {
          // If combining fails, fall through to use the originally parsed end
        }
      }

      return Interval.fromDateTimes(start, end);
    }

    if (startIsValid) {
      const dur = Duration.fromISO(e, opts);
      if (dur.isValid) {
        return Interval.after(start, dur);
      }
    } else if (endIsValid) {
      const dur = Duration.fromISO(s, opts);
      if (dur.isValid) {
        return Interval.before(end, dur);
      }
    }
  }
  return Interval.invalid("unparsable", `the input "${text}" can't be parsed as ISO 8601`);
}

