/* Test suite for interval ISO 8601 partial date/time parsing */
import { Interval } from "../../src/luxon";

describe("Interval.fromISO with partial end date/time", () => {
  test("parses interval with time-only end (HH format)", () => {
    const interval = Interval.fromISO("1988-04-15T09/15");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("1988-04-15T09:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("1988-04-15T15:00:00.000+00:00");
  });

  test("parses interval with time-only end (HH:MM format)", () => {
    const interval = Interval.fromISO("2021-03-23T09:30/12:45");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2021-03-23T09:30:00.000+00:00");
    expect(interval.end.toISO()).toBe("2021-03-23T12:45:00.000+00:00");
  });

  test("parses interval with time-only end (HH:MM:SS format)", () => {
    const interval = Interval.fromISO("2020-05-10T08:00:00/10:30:00");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2020-05-10T08:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("2020-05-10T10:30:00.000+00:00");
  });

  test("parses interval with partial date end (MM-DD format)", () => {
    const interval = Interval.fromISO("2020-05-10/05-15");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2020-05-10T00:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("2020-05-15T00:00:00.000+00:00");
  });

  test("parses interval with partial date end using proper ISO format (--MM-DD)", () => {
    const interval = Interval.fromISO("2020-05-10/--06-15");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2020-05-10T00:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("2020-06-15T00:00:00.000+00:00");
  });

  test("still supports complete end dates", () => {
    const interval = Interval.fromISO("2020-05-10/2020-05-15");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2020-05-10T00:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("2020-05-15T00:00:00.000+00:00");
  });

  test("still supports duration format", () => {
    const interval = Interval.fromISO("2020-05-10T09:00:00/PT2H30M");
    expect(interval.isValid).toBe(true);
    expect(interval.start.toISO()).toBe("2020-05-10T09:00:00.000+00:00");
    expect(interval.end.toISO()).toBe("2020-05-10T11:30:00.000+00:00");
  });

  test("preserves timezone information", () => {
    const interval = Interval.fromISO("2020-05-10T09:00:00+02:00/12:00");
    expect(interval.isValid).toBe(true);
    expect(interval.start.zoneName).toBe("UTC+2");
    expect(interval.end.zoneName).toBe("UTC+2");
  });
});

